let state = null;

export function initialize(wrapper, dotNetRef, timeoutMs) {
    const activityEvents = ["mousemove", "keydown", "click", "scroll"];
    let timerId = null;
    let isIdle = false;

    function resetTimer() {
        if (timerId !== null) {
            clearTimeout(timerId);
        }

        if (isIdle) {
            isIdle = false;
            dotNetRef.invokeMethodAsync("OnActiveCallback");
        }

        timerId = setTimeout(() => {
            isIdle = true;
            dotNetRef.invokeMethodAsync("OnIdleCallback");
        }, timeoutMs);
    }

    for (const event of activityEvents) {
        wrapper.addEventListener(event, resetTimer, { passive: true });
    }

    // Start the initial idle countdown.
    resetTimer();

    state = { wrapper, activityEvents, resetTimer, timerId: () => timerId, clearTimer: () => clearTimeout(timerId) };
}

export function dispose() {
    if (state === null) return;

    const { wrapper, activityEvents, resetTimer, clearTimer } = state;

    for (const event of activityEvents) {
        wrapper.removeEventListener(event, resetTimer);
    }

    clearTimer();
    state = null;
}

